      "tracks": [
        "video",
        "page"
      ],
      "newIdea": "The meter is linear in each input, so doubling one arrow exactly doubles the score, and that clean scaling is the crack the cheapest fix will exploit.",
      "novelElements": [
        "the job-fit columns",
        "the doubled arrow",
        "the unearned-win flag"
      ],
      "onScreenText": [
        "two arrows in, one number out",
        "different aisle, same meter",
        "keep the direction, forget the size",
        "Still up?"
      ],
      "colors": {
        "candidates": "data.observed",
        "score": "data.params",
        "failureFlag": "data.error",
        "background": "bg",
        "labels": "text"
      },
      "predictionPrompt": {
        "prompt": "If you double c1's length exactly, same direction, just twice as long, does the number double too?",
        "expectedWrongAnswer": "No: stretching one arrow nudges the number up in some messy way, not a clean doubling."
      },
      "majorReveal": true,
      "misconceptionBeat": false,
      "estimatedSeconds": 70
    }
  ],
  "scriptSections": [
    {
